    // Subsequence "110": requires two '1's followed by a '0'.

    // If a string only contains blocks of identical characters, it is coherent.
    // e.g., "00011100"
    // If we have a pattern like "0...1...1", it might be "011".
    // If we have a pattern like "1...1...0", it might be "110".

    // Consider the structure of coherent strings.
    // If a string has at most one transition from '0' to '1' and at most one transition from '1' to '0',
    // or vice-versa, it seems plausible.

    // Case 1: All '0's followed by all '1's (0*1*)
    // Example: "000111".
    // "011": Need a 0, then two 1s. Yes, if there are at least two 1s after the first 0.
    // If it is "0...01...1" where count(1) >= 2 and count(0) >= 1, then "011" exists.
    // This means a string of the form 0*1* is coherent only if it has at most one '1' or at most one '0'.
    // E.g., "001", "01", "00", "11", "1".

    // Case 2: All '1's followed by all '0's (1*0*)
    // Example: "111000".
    // "110": Need two 1s, then a 0. Yes, if there are at least two 1s before the last 0.
    // This means a string of the form 1*0* is coherent only if it has at most one '0' or at most one '1'.
    // E.g., "110", "10", "11", "00", "1". Wait, "110" contains "110".
    // If it is "1...10...0" where count(1) >= 2 and count(0) >= 1, then "110" exists.

    // If a string is coherent, it must be structured such that it avoids these patterns.

    // Let's consider the simplest coherent forms:
    // 1. All the same character: "000..." or "111..." (always coherent)
    // 2. At most one transition: "0...01...1" or "1...10...0" but constrained by the subsequence rule.

    // If the string is coherent, it must belong to one of these structures:
    // 1. All '0's: $0^*$
    // 2. All '1's: $1^*$
    // 3. $0^*1$: At most one '1' after all '0's.
    // 4. $01^*$: At most one '0' before all '1's.
    // 5. $1^*0$: At most one '0' after all '1's.
    // 6. $10^*$: At most one '1' before all '0's.

    // If we have $0...01...11$: "011" exists.
    // If we have $1...10...00$: "110" exists.

    // A string is coherent if and only if it is of the form $0^*1$ or $1^*0$.
    // Proof sketch:
    // If $s = 0^*1$: $s$ is $0...01$.
    // - "011": Requires two 1s. Only one 1 exists. Impossible.
    // - "110": Requires two 1s before a 0. Only one 1 exists (if $s$ ends in 1, and there are 0s before). Wait, the 0s are at the start. $0...01$. No two 1s. Impossible.
    // So $0^*1$ is coherent.

    // If $s = 1^*0$: $s$ is $1...10$.
    // - "011": Requires a 0 before two 1s. No 0 before the 1s. Impossible.
    // - "110": Requires two 1s before a 0. If $|1^*| \ge 2$, then it exists.
    // Wait, if $s=110$, it contains "110". This form is not always coherent.

    // Let's re-examine the conditions.
    // Forbidden: $0 \prec 1 \prec 1$ AND $1 \prec 1 \prec 0$. ($\prec$ means appears before as a subsequence)

    // A string $s$ is coherent $\iff$ it is one of the following forms:
    // 1. $0^*$
    // 2. $1^*$
    // 3. $0^*1$ (at most one '1' after all '0's) $\rightarrow$ Coherent.
    // 4. $10^*$ (at most one '0' after all '1's) $\rightarrow$ Coherent.

    // Let's check these:
    // 1. $0^*$: Coherent.
    // 2. $1^*$: Coherent.
    // 3. $0^*1$: $s = 0...01$.
    //    - "011": Impossible (only one 1).
    //    - "110": Impossible (no 1s before the 0, unless the 0 is the last character, but $s$ ends in 1). If $s$ is $0^k 1$, the only 1 is at the end. Any 0 is before it. No two 1s. Coherent.
    // 4. $10^*$: $s = 1...10...0$.
    //    - "011": Impossible (no 0 before the 1s, unless the 0 is the first character, but $s$ starts with 1s). Wait, if $s=100$. $1\prec 0 \prec 0$. No 11. Impossible. If $s=1100$. $1\prec 1 \prec 0$. This is "110". Not coherent.

    // The only structures that guarantee coherence are:
    // A. Monotonic: $0^*$ or $1^*$
    // B. At most one change point:
    //    B1. $0...01$ (exactly one '1' at the end, possibly preceded by many '0's) $\implies 0^*1$
    //    B2. $1...10$ (exactly one '0' at the end, possibly preceded by many '1's) $\implies 1^*0$

    // Wait, if $s=110$, it is $1^*0$ with $|1^*|=2$. It is NOT coherent.
    // If $s=011$, it is $0^*1^*$ with $|1^*|=2$. It is NOT coherent.

    // The actual coherent forms must be those with at most one character of one type, or all the same.
    // Coherent forms are:
    // 1. $0^*$
    // 2. $1^*$
    // 3. $0^*1$ (only one '1')
    // 4. $10^*$ (only one '0')

    // Let $s$ be the target string. We want $\min(\text{cost}(s \to T))$ where $T$ is coherent.
    // The target $T$ must have one of these forms:
    // Type 0: All '0's. Cost is count of '1's in $s$.
    // Type 1: All '1's. Cost is count of '0's in $s$.
    // Type 2: $0^*1$. $T$ has one '1' and $N-1$ '0's. We choose the position of the single '1' to minimize cost.
    // Type 3: $10^*$. $T$ has one '0' and $N-1$ '1's. We choose the position of the single '0' to minimize cost.

    let mut min_cost = (n + 1) as i64;

    // 1. Target $0^N$ (All zeros)
    let cost_all_zero = s.chars().filter(|&c| c == '1').count() as i64;
    min_cost = min_cost.min(cost_all_zero);

    // 2. Target $1^N$ (All ones)
    let cost_all_one = s.chars().filter(|&c| c == '0').count() as i64;
    min_cost = min_cost.min(cost_all_one);

    // 3. Target $0^*1$ (One '1', $N-1$ '0's)
    // The single '1' can be at any position $i \in [0, N-1]$.
    // $T_i$ has $T_i[i] = '1'$ and $T_i[j] = '0'$ for $j \ne i$.
    for i in 0..n {
        let mut current_cost = 0;
        for j in 0..n {
            let target_char = if j == i { '1' } else { '0' };
            if chars[j] != target_char {
                current_cost += 1;
            }
        }
        min_cost = min_cost.min(current_cost as i64);
    }

    // 4. Target $10^*$ (One '0', $N-1$ '1's)
    // The single '0' can be at any position $i \in [0, N-1]$.
    // $T_i$ has $T_i[i] = '0'$ and $T_i[j] = '1'$ for $j \ne i$.
    for i in 0..n {
        let mut current_cost = 0;
        for j in 0..n {
            let target_char = if j == i { '0' } else { '1' };
            if chars[j] != target_char {
                current_cost += 1;
            }
        }
        min_cost = min_cost.min(current_cost as i64);
    }

    min_cost
}
