fn solve(s: String) -> i64 {
    let n = s.len();
    if n == 0 {
        return 0;
    }

    // A string is "cohesive" if it does not contain "011" or "110" as a subsequence.
    // Let's analyze the structure of a cohesive string.

    // Subsequences:
    // "011": requires 0 appears before two 1s.
    // "110": requires two 1s appear before a 0.

    // If a string is cohesive, it must not have the pattern 0...1...1 or 1...1...0.
    // This severely restricts the possible structures.

    // Case 1: Only 0s and 1s are present.
    // If there are two 1s followed by a 0 (1...1...0), it has "110".
    // If there is a 0 followed by two 1s (0...1...1), it has "011".

    // Consider the possible structures of a string without these subsequences.

    // 1. All 0s: "000..." -> Cohesive (no 1s, so no "011" or "110")
    // 2. All 1s: "111..." -> Cohesive (no 0s, so no "011" or "110")

    // 3. Mixed:
    // If it contains both 0s and 1s, they must be arranged such that neither forbidden subsequence can be formed.

    // If the string is of the form $0...01...1$ (all 0s followed by all 1s):
    // - "011": Requires 0 followed by two 1s. If there is at least one 0 and at least two 1s, this is possible.
    //   E.g., "011". If $s = 0^a 1^b$, with $a \ge 1, b \ge 2$. Choose $s[0]$ (0), $s[a]$ (1), $s[a+1]$ (1). This forms "011".
    // - "110": Requires two 1s followed by a 0. If there are at least two 1s and at least one 0, this is possible.
    //   E.g., "110". If $s = 0^a 1^b$. The 0s come before the 1s. No 1 comes before a 0. This is safe from "110".

    // If $s = 0^a 1^b$:
    // - If $a=0$ or $b < 2$, it's cohesive.
    // - If $a \ge 1$ and $b \ge 2$: "011" exists. (e.g., $s[0]=0, s[a]=1, s[a+1]=1$). Not cohesive.

    // If the string is of the form $1...10...0$ (all 1s followed by all 0s):
    // If $s = 1^b 0^a$:
    // - "011": Requires 0 followed by two 1s. All 0s are after all 1s. Impossible. Safe from "011".
    // - "110": Requires two 1s followed by 0. If $b \ge 2$ and $a \ge 1$. Choose $s[0], s[1]$ (1s), $s[b]$ (0). This forms "110". Not cohesive.

    // Summary of cohesive forms:
    // 1. All 0s ($0^n$)
    // 2. All 1s ($1^n$)
    // 3. $0^a 1^1$ (where $a \ge 1, b=1$). "01". No "011" (need 2 1s). No "110" (need 2 1s). Cohesive.
    // 4. $0^a 1^0$ (All 0s).
    // 5. $1^1 0^a$ (where $a \ge 1, b=1$). "10". No "011" (need 0 before 1s). No "110" (need 2 1s). Cohesive.
    // 6. $1^b 0^1$ (where $b \ge 1, a=1$). "110" exists if $b \ge 2$. If $b=1$, "10", which is case 5.

    // Let's re-check the structure requirements carefully.

    // A string $S$ is cohesive $\iff$
    // NOT ($\exists i_0 < i_1 < i_2$ such that $S[i_0]=0, S[i_1]=1, S[i_2]=1$) AND
    // NOT ($\exists i_1 < i_2 < i_0$ such that $S[i_1]=1, S[i_2]=1, S[i_0]=0$)

    // 1. No "011": This implies that once we see a '0', there can be at most one '1' afterwards.
    //    If we have $0 \dots 1 \dots 1$, it fails. So, all 1s must appear before any 0, OR there is only one 1 after the first 0.
    //    This means the structure must be $1^* 0^* 1^*$, but the second $1^*$ is restricted.
    //    If $0$ appears, subsequent characters can only be $0$ or $1$ (at most one $1$).
    //    If we have $0...1...1$, we fail. So, the structure must be $1^* 0^*$. If there is a 0, all subsequent 1s must be $\le 1$.

    // 2. No "110": This implies that once we see a '0', there must be at most one '1' before it.
    //    If we have $1 \dots 1 \dots 0$, it fails. So, all 1s must appear after any 0, OR there are at most one 1 before the last 0.

    // Combining these constraints:
    // If the string contains a 0, and later contains a 1, there can be at most one 1 after that 0. (From No "011")
    // If the string contains a 1, and later contains a 0, there can be at most one 1 before that 0. (From No "110")

    // This strongly suggests the string must be one of these forms:
    // A. All 0s ($0^n$)
    // B. All 1s ($1^n$)
    // C. $0^* 1^*$ (Prefix of 0s, followed by 1s). Fails if $|0| \ge 1$ and $|1| \ge 2$.
    // D. $1^* 0^*$ (Prefix of 1s, followed by 0s). Fails if $|1| \ge 2$ and $|0| \ge 1$.

    // The only structures that seem robustly cohesive are those that are nearly monotonic:
    // 1. All 0s.
    // 2. All 1s.
    // 3. $0^a 1$ (If $a \ge 0$).
    // 4. $1 0^b$ (If $b \ge 0$).

    // Let's test $0^a 1$:
    // - "01": Cohesive.
    // - "001": Cohesive. (No "011" since only one 1. No "110" since no 1 before 0).
    // - "011": Not cohesive (0...1...1).
    // So, the form must be $0^a 1^b$ where $b \le 1$.

    // Let's test $1 0^b$:
    // - "10": Cohesive.
    // - "100": Cohesive. (No "011" since no 1 after 0. No "110" since only one 1 before 0).
    // - "110": Not cohesive (1...1...0).
    // So, the form must be $1^b 0^a$ where $b \le 1$.

    // The possible target cohesive forms are:
    // 1. $0^n$
    // 2. $1^n$
    // 3. $0^a 1$ (or just $0^a$)
    // 4. $1 0^b$ (or just $0^b$)

    // Since we want the minimum flips, we check the cost to achieve the best possible structure.

    // Cost to achieve $0^n$: Count of '1's in $s$.
    let cost_to_0_n = s.chars().filter(|&c| c == '1').count() as i64;

    // Cost to achieve $1^n$: Count of '0's in $s$.
    let cost_to_1_n = n as i64 - s.chars().filter(|&c| c == '1').count() as i64;

    // Cost to achieve $0^a 1$ or $0^a$:
    // Best is usually to aim for the structure that requires the fewest changes from the original string.

    // Candidate 1: Structure $0^* 1$ (or $0^*$ if $n=1$ and $s$ is '0').
    // We try to make $s$ match $0...01$.
    // If we fix the last character to '1' (if $n>0$), the cost is the count of '1's before it + count of '0's after it.
    // This is complicated because we don't know where the split point is.

    // Simpler approach: Iterate over all possible "transition" points $k$ ($0 \le k \le n$).
    // We target a structure $P_k$, which is the best cohesive form achievable with a transition point at $k$.

    // Target forms:
    // A. $0^n$ (all 0s) -> Cost: count('1')
    // B. $1^n$ (all 1s) -> Cost: count('0')

    // C. $0^a 1^b$ where $b \le 1$.
    // C1. $0^n$: Covered by A.
    // C2. $0^a 1$ ($a=n-1, b=1$): Target is $s'$ where $s'[i]=0$ for $i<n-1$ and $s'[n-1]=1$.
    //     Cost: Count of $s[i]=1$ for $i < n-1$ + Count of $s[n-1]=0$.

    // D. $1^a 0^b$ where $a \le 1$.
    // D1. $0^n$: Covered by A.
    // D2. $1 0^b$ ($a=1, b=n-1$): Target is $s'$ where $s'[0]=1$ and $s'[i]=0$ for $i>0$.
    //     Cost: Count of $s[0]=0$ + Count of $s[i]=1$ for $i > 0$.

    // Since $n$ is up to $10^5$, we can afford $O(N)$ checks.

    let mut min_flips = cost_to_0_n.min(cost_to_1_n);

    // Check structures of the form $0^* 1^b$ where $b \le 1$.

    // Case 1: Target is $0^n$. (Already handled)

    // Case 2: Target is $0^* 1$. (Requires $n \ge 1$)
    if n >= 1 {
        // Iterate through all possible split points $k$ where $s[k-1]$ is the last 0 and $s[k]$ is the single 1.
        // This means the target is $0^{k} 1^{n-k}$. For cohesion, $n-k$ must be 1. So $k=n-1$.
        // Target: $0^{n-1} 1$.
        if n > 0 {
            let target_0_n_minus_1_1 = (0..n-1).map(|i| s.as_bytes()[i] == b'1').count() as i64 +
                                        (s.as_bytes()[n-1] == b'0') as i64;
            min_flips = min_flips.min(target_0_n_minus_1_1);
        }
    }

    // Check structures of the form $1^a 0^b$ where $a \le 1$.

    // Case 3: Target is $1^n$. (Already handled)

    // Case 4: Target is $1 0^*$. (Requires $n \ge 1$)
    if n >= 1 {
        // Target: $1 0^{n-1}$.
        let target_1_0_n_minus_1 = (s.as_bytes()[0] == b'0') as i64 +
                                   (1..n).map(|i| s.as_bytes()[i] == b'1').count() as i64;
        min_flips = min_flips.min(target_1_0_n_minus_1);
    }

    // The analysis above suggests the minimum must be one of these simple monotonic forms.
    // The only possible structures that avoid "011" and "110" are essentially:
    // 1. All 0s
    // 2. All 1s
